mapper.insert:
/* rcpMapper.callDvcChgTrgtProc */
{ CALL P_DVC_CHG_TRGT_PROC(
				#{O_PROC_CNT, mode=OUT, jdbcType=INTEGER}
				, #{O_CODE, mode=OUT, jdbcType=VARCHAR}
				, #{O_MSG, mode=OUT, jdbcType=VARCHAR}
		)}

mapper.select:
/* rcpMgmtMapper.selectRcpListExcel */
SELECT ( SELECT X.CD_DSC FROM CMN_GRP_CD_MST X WHERE X.GRP_ID = 'CMN0032' AND X.CD_VAL = REQ.SERVICE_TYPE ) AS SERVICE_NAME , REQ.RES_NO , CST.CSTMR_NAME , TRIM(CST.CSTMR_FOREIGNER_RRN) AS CSTMR_FOREIGNER_RRN , TRIM(CST.CSTMR_NATIVE_RRN) AS CSTMR_NATIVE_RRN /* 주민번호 */ , DECODE(REQ.CSTMR_TYPE, 'FN', TRIM(CST.CSTMR_FOREIGNER_RRN), TRIM(CST.CSTMR_NATIVE_RRN)) AS SSN , SUBSTR(REPLACE(CRYPTO_AES256.DEC_AES(DECODE(REQ.CSTMR_TYPE, 'FN', TRIM(CST.CSTMR_FOREIGNER_RRN), TRIM(CST.CSTMR_NATIVE_RRN))), '-', ''), 0, 6) as BIRTH_DT , SUBSTR(REPLACE(CRYPTO_AES256.DEC_AES(DECODE(REQ.CSTMR_TYPE, 'FN', TRIM(CST.CSTMR_FOREIGNER_RRN), TRIM(CST.CSTMR_NATIVE_RRN))), '-', ''), 7, 1) as CSTMR_GENDER_STR , ( SELECT X.CD_DSC FROM CMN_GRP_CD_MST X WHERE X.GRP_ID = 'RCP9004' AND X.CD_VAL = REQ.REQ_BUY_TYPE ) AS REQ_BUY_TYPE , ( SELECT X.CD_DSC FROM CMN_GRP_CD_MST X WHERE X.GRP_ID = 'RCP9005' AND X.CD_VAL = MOV.MOVE_COMPANY ) AS MOVE_COMPANY , ( SELECT PRDT_NM || '(' || PRDT_CODE || ')' FROM CMN_INTM_MDL WHERE PRDT_ID = SAL.MODEL_ID ) AS PRDT_NM , ( SELECT X.CD_DSC FROM CMN_GRP_CD_MST X WHERE X.GRP_ID = 'CMN0044' AND X.USG_YN = 'Y' AND X.CD_VAL = REQ.REQ_MODEL_COLOR ) AS PRDT_COLR_NM , DECODE(TRIM(CST.CSTMR_MOBILE_FN) || TRIM(CST.CSTMR_MOBILE_MN) || TRIM(CST.CSTMR_MOBILE_RN), '', TRIM(CST.CSTMR_TEL_FN) || '-' || TRIM(CST.CSTMR_TEL_MN) || '-' || TRIM(CST.CSTMR_TEL_RN), TRIM(CST.CSTMR_MOBILE_FN) || '-' || TRIM(CST.CSTMR_MOBILE_MN) || '-' || TRIM(CST.CSTMR_MOBILE_RN) ) AS CSTMR_MOBILE , ( SELECT ORGN_NM FROM ORG_ORGN_INFO_MST WHERE ORGN_ID = REQ.CNTPNT_SHOP_ID ) || '/' || REQ.CNTPNT_SHOP_ID AS AGENT_NAME /* 대리점 */ , ( SELECT RATE_NM FROM MSP_RATE_MST WHERE RATE_CD = SAL.SOC_CODE AND SERVICE_TYPE = 'P' AND ROWNUM = 1 ) || '(' || SAL.SOC_CODE || ')' AS SOC_NAME /* 요금제 */ , ( SELECT X.CD_DSC FROM CMN_GRP_CD_MST X WHERE X.GRP_ID = 'RCP9001' AND X.CD_VAL = REQ.OPER_TYPE ) AS OPER_NAME /* 업무구분 */ , TO_CHAR(REQ.REQ_IN_DAY, 'YYYY-MM-DD') AS REQ_IN_DAY /* 신청일자 */ , ( SELECT X.CD_DSC FROM CMN_GRP_CD_MST X WHERE X.GRP_ID = 'RCP0005' AND X.CD_VAL = REQ.PSTATE) AS PSTATE_NAME /* 신청서상태 */ , ( SELECT X.CD_DSC FROM CMN_GRP_CD_MST X WHERE X.GRP_ID = 'RCP0006' AND X.CD_VAL = REQ.REQUEST_STATE_CODE) AS REQUEST_STATE_NAME /* 진행상태*/ , ( SELECT X.CD_DSC FROM CMN_GRP_CD_MST X WHERE X.GRP_ID = 'RCP0007' AND X.CD_VAL = NVL(REQ.ON_OFF_TYPE, '0')) AS ON_OFF_NAME /* 온/오프라인 */ , REQ.ON_OFF_TYPE , REQ.OPEN_MARKET_REFERER /* 유입경로 */ , NVL(REQ.REC_YN, 'N') AS REC_YN /* 녹취여부 */ , NVL(REQ.SHOP_NM, FN_GET_ORGNM(REQ.SHOP_CD)) || '/' || REQ.SHOP_CD AS SHOP_NM /* 판매점 */ , ( SELECT USR_NM FROM CMN_USR_MST WHERE USR_ID = REQ.SHOP_USM_ID ) || '/' || REQ.SHOP_USM_ID AS USR_NM /* 판매자 */ , REQ.REQUEST_KEY , CST.CSTMR_ADDR || ' ' || CST.CSTMR_ADDR_DTL AS CSTMR_ADDR , DLV.DLVRY_ADDR || ' ' || DLV.DLVRY_ADDR_DTL AS DLVRY_ADDR , SUBSTR(DLV.DLVRY_POST,1,3) || '-' || SUBSTR(DLV.DLVRY_POST,4,3) AS DLVRY_POST , TRIM(DLV.DLVRY_MOBILE_FN) || '-' || TRIM(DLV.DLVRY_MOBILE_MN) || '-' || TRIM(DLV.DLVRY_MOBILE_RN) AS DLVRY_MOBILE , TRIM(CST.CSTMR_TEL_FN) || '-' || TRIM(CST.CSTMR_TEL_MN) || '-' || TRIM(CST.CSTMR_TEL_RN) AS CSTMR_TEL_NO , ( SELECT X.CD_DSC FROM CMN_GRP_CD_MST X WHERE X.GRP_ID = 'CMN0058' AND X.CD_VAL = SAL.SPRT_TP ) AS SPRT_TP_NM , ( SELECT X.CD_DSC FROM CMN_GRP_CD_MST X WHERE X.GRP_ID = 'RCP9011' AND X.CD_VAL = CST.RECOMMEND_FLAG_CD) AS RECOMMEND_FLAG_NM /* 추천인구분명 */ , CST.RECOMMEND_INFO AS RECOMMEND_INFO /* 추천인정보 */ , NVL(REQ.PROD_TYPE, '01') AS PROD_TYPE , ( SELECT X.CD_DSC FROM CMN_GRP_CD_MST X WHERE X.GRP_ID = 'RCP0063' AND X.CD_VAL = NVL(REQ.PROD_TYPE, '01')) AS PROD_TYPE_NM , REQ.CLAUSE_RENTAL_MODEL_CP , REQ.CLAUSE_RENTAL_MODEL_CP_PR , REQ.CLAUSE_RENTAL_SERVICE , SAL.RENTAL_BASE_AMT , SAL.RENTAL_BASE_DC_AMT , SAL.RENTAL_MODEL_CP_AMT , (SELECT USR_NM FROM CMN_USR_MST WHERE USR_ID = REQ.RVISN_ID) AS RVISN_NM , TO_CHAR(REQ.RVISN_DTTM, 'YYYY-MM-DD HH24:MI:SS') AS RVISN_DTTM , PRMT.PROMOTION_NM , RTRIM(DECODE(PRMT.BENEFIT_01, 'Y', '추가데이터제공,', '') || DECODE(PRMT.BENEFIT_02, 'Y', '추가기본료할인,', '') || DECODE(PRMT.BENEFIT_03, 'Y', '가입비면제,', '') || DECODE(PRMT.BENEFIT_04, 'Y', '유심비면제,', ''), ',') AS BENEFIT_CMMT
, ( SELECT LISTAGG(CD_NM, ',') WITHIN GROUP(ORDER BY CD) FROM MCP_REQUEST_BENEFIT@DL_MCP WHERE REQUEST_KEY = REQ.REQUEST_KEY GROUP BY REQUEST_KEY ) AS BENEFIT_NAME , REQ.SPC_CODE AS SLS_NO /* 특판코드 */ , (SELECT SLS_NM FROM MSP_KT_PLCY_MST WHERE SLS_NO = REQ.SPC_CODE) AS SLS_NM /* 특판코드명 */ FROM MCP_REQUEST@DL_MCP REQ , MCP_REQUEST_CSTMR@DL_MCP CST , MCP_REQUEST_SALEINFO@DL_MCP SAL , MCP_REQUEST_MOVE@DL_MCP MOV , MCP_REQUEST_DLVRY@DL_MCP DLV , MSP_PROMOTION_MST PRMT WHERE REQ.REQUEST_KEY = CST.REQUEST_KEY AND REQ.REQUEST_KEY = SAL.REQUEST_KEY AND REQ.REQUEST_KEY = MOV.REQUEST_KEY AND REQ.REQUEST_KEY = DLV.REQUEST_KEY AND REQ.PROMOTION_CD = PRMT.PROMOTION_CD(+)
AND REQ.REQ_IN_DAY BETWEEN TO_DATE(#{searchStartDt},'YYYYMMDD') AND TO_DATE(#{searchEndDt},'YYYYMMDD') + 1 /*신청일자*/
AND REQ.SERVICE_TYPE = #{pServiceType} /*서비스타입-선후불*/
AND REQ.OPER_TYPE = #{pOperType} /*신청유형-신규가입/번호이동정보/기기변경정보*/
AND REQ.CNTPNT_SHOP_ID = #{cntpntShopId}
AND REQ.SHOP_CD = #{pAgentCode}
AND (REQ.SHOP_CD = #{pAgentCode} OR REQ.CNTPNT_SHOP_ID = #{pAgentCode})
AND REQ.SHOP_CD = #{pAgentCode}
AND REQ.REQUEST_STATE_CODE = #{pRequestStateCode} /*접수상태코드-진행상태*/
AND CST.CSTMR_NAME LIKE #{pSearchName} || '%' /*검색구분-고객명(pSearchGbn=1로 구분)*/
AND REQ.CONTRACT_NUM = #{pSearchName} /*검색구분-예약번호(pSearchGbn=2로 구분)*/
AND (CST.CSTMR_MOBILE_FN || CST.CSTMR_MOBILE_MN || CST.CSTMR_MOBILE_RN LIKE '%'|| TRANSLATE(#{pSearchName},'1234567890-','1234567890')||'%' OR CST.CSTMR_TEL_FN || CST.CSTMR_TEL_MN || CST.CSTMR_TEL_RN LIKE '%'|| TRANSLATE(#{pSearchName},'1234567890-','1234567890')||'%') /*검색구분-연락처(searchGbn=3로 구분)*/
AND REQ.REQ_PHONE_SN = #{pSearchName}
AND REQ.RES_NO = #{pSearchName}
AND SAL.SOC_CODE IN ( SELECT RATE_CD FROM MSP_RATE_MST WHERE SERVICE_TYPE = 'P' AND RATE_NM LIKE UPPER(#{pSearchName}) || '%' )
AND REQ.PSTATE = #{pPstate}
AND REQ.REQ_BUY_TYPE = #{reqBuyType}
AND SAL.SPRT_TP = #{sprtTp}
AND NVL(REQ.PROD_TYPE, '01') = #{prodType}
AND REQ.ON_OFF_TYPE = #{onOffType}
ORDER BY REQ.REQUEST_KEY DESC

SELECT DISTINCT CONTRACT_NUM 
  FROM MSP_JUO_SUB_INFO_HIST 
 WHERE SVC_CNTR_NO = #{pSearchName}
